from flask import Flask, request, jsonify
import jwt
from jwt.exceptions import InvalidTokenError

class JWTManager:
    def __init__(self, secret_key, algorithms=None, public_key=None):
        self.secret_key = secret_key
        self.public_key = public_key or secret_key
        self.algorithms = algorithms or ['HS256']

    def decode_token(self, token):
        try:
            if 'RS' in self.algorithms:
                payload = jwt.decode(token, self.public_key, algorithms=self.algorithms)
            else:
                payload = jwt.decode(token, self.secret_key, algorithms=self.algorithms)
            return payload
        except InvalidTokenError as e:
            raise ValueError(f"Token is invalid: {str(e)}")

app = Flask(__name__)

# Example usage: Different configurations for internal and public APIs
internal_jwt_manager = JWTManager(secret_key='internal_secret', algorithms=['HS256'])
public_jwt_manager = JWTManager(secret_key='public_secret_or_private_key', algorithms=['RS256'], public_key='public_key')

@app.route('/verify-internal', methods=['POST'])
def verify_internal():
    token = request.headers.get('Authorization').split()[1]
    try:
        payload = internal_jwt_manager.decode_token(token)
        return jsonify(payload), 200
    except ValueError as e:
        return jsonify({'error': str(e)}), 401

@app.route('/verify-public', methods=['POST'])
def verify_public():
    token = request.headers.get('Authorization').split()[1]
    try:
        payload = public_jwt_manager.decode_token(token)
        return jsonify(payload), 200
    except ValueError as e:
        return jsonify({'error': str(e)}), 401

